module top_module(operand1, b, op, result);input signed [12:0] operand1, b;
  input [4:0] op;
  output reg signed [12:0] result; // Change output to reg

  always @(*) begin
    case (op)
      5'b00000: result = operand1 + b;
      5'b00001: result = operand1 - b;
      5'b00010: result = operand1 & b;
      5'b00011: result = operand1 | b;
      5'b00100: result = operand1 ^ b;
      5'b00101: result = (b[2:0] > 0) ? (operand1 << b[2:0]) : operand1;
      5'b00110: result = (b[2:0] > 0) ? (operand1 >> b[2:0]) : operand1;
      default: result = 0;
    endcase
  end
endmodule
